        "上海": "多云，28°C",
        "深圳": "阵雨，30°C",
    }
    return weather_data.get(city, "暂无数据")

# 定义一个工具：计算数学表达式
@tool
def calculator(expression: str) -> str:
    """计算数学表达式"""
    try:
        return str(eval(expression))
    except:
        return "计算错误"
