def remember(self, info: str):
        self.short_term.append(info)  # 先记脑子里
        self.long_term.store(info)    # 再存进"笔记本"

def recall(self, query: str) -> list:
        return self.long_term.search(query)  # 翻翻旧账，看有没有用过的
